    59→		flags:        map[string]*flipt.Flag{},
    60→		segments:     map[string]*flipt.Segment{},
    61→		rules:        map[string]*flipt.Rule{},
    62→		rollouts:     map[string]*flipt.Rollout{},
    63→		evalRules:    map[string][]*storage.EvaluationRule{},
    64→		evalRollouts: map[string][]*storage.EvaluationRollout{},
    65→	}
    66→}
