    78→// SnapshotFromFS is a convenience function for building a snapshot
    79→// directly from an implementation of fs.FS using the list state files
    80→// function to source the relevant Flipt configuration files.
    81→func SnapshotFromFS(logger *zap.Logger, src fs.FS, opts ...containers.Option[SnapshotOption]) (*Snapshot, error) {
    82→	paths, err := listStateFiles(logger, src)
    83→	if err != nil {
    84→		return nil, err
    85→	}
    86→
    87→	return SnapshotFromPaths(logger, src, paths, opts...)
    88→}
