    90→// SnapshotFromPaths constructs a StoreSnapshot from the provided
    91→// slice of paths resolved against the provided fs.FS.
    92→func SnapshotFromPaths(logger *zap.Logger, ffs fs.FS, paths []string, opts ...containers.Option[SnapshotOption]) (*Snapshot, error) {
    93→	logger.Debug("opening state files", zap.Strings("paths", paths))
    94→
    95→	var files []fs.File
    96→	for _, file := range paths {
    97→		fi, err := ffs.Open(file)
    98→		if err != nil {
    99→			return nil, err
   100→		}
   101→
   102→		files = append(files, fi)
   103→	}
   104→
   105→	return SnapshotFromFiles(logger, files, opts...)
   106→}
   107→
   108→// SnapshotFromFiles constructs a StoreSnapshot from the provided slice
   109→// of fs.File implementations.
   110→func SnapshotFromFiles(logger *zap.Logger, files []fs.File, opts ...containers.Option[SnapshotOption]) (*Snapshot, error) {
   111→	now := flipt.Now()
   112→	s := Snapshot{
   113→		ns: map[string]*namespace{
   114→			defaultNs: newNamespace("default", "Default", now),
   115→		},
   116→		evalDists: map[string][]*storage.EvaluationDistribution{},
   117→		now:       now,
   118→	}
   119→
   120→	var so SnapshotOption
   121→	containers.ApplyAll(&so, opts...)
   122→
   123→	for _, fi := range files {
   124→		defer fi.Close()
   125→		info, err := fi.Stat()
   126→		if err != nil {
   127→			return nil, err
   128→		}
   129→
   130→		logger.Debug("opening state file", zap.String("path", info.Name()))
   131→
   132→		docs, err := documentsFromFile(fi, so)
   133→		if err != nil {
   134→			return nil, err
   135→		}
   136→
   137→		for _, doc := range docs {
   138→			if err := s.addDoc(doc); err != nil {
   139→				return nil, err
   140→			}
   141→		}
   142→	}
   143→
   144→	return &s, nil
   145→}
