   147→// WalkDocuments walks all the Flipt feature documents found in the target fs.FS
   148→// based on either the default index file or an index file located in the root
   149→func WalkDocuments(logger *zap.Logger, src fs.FS, fn func(*ext.Document) error) error {
   150→	paths, err := listStateFiles(logger, src)
   151→	if err != nil {
   152→		return err
   153→	}
   154→
   155→	for _, file := range paths {
   156→		logger.Debug("opening state file", zap.String("path", file))
   157→
   158→		fi, err := src.Open(file)
   159→		if err != nil {
   160→			return err
   161→		}
   162→		defer fi.Close()
   163→
   164→		docs, err := documentsFromFile(fi, SnapshotOption{})
   165→		if err != nil {
   166→			return err
   167→		}
   168→
   169→		for _, doc := range docs {
   170→			if err := fn(doc); err != nil {
   171→				return err
   172→			}
   173→		}
   174→	}
   175→
   176→	return nil
   177→}
   178→
   179→// documentsFromFile parses and validates a document from a single fs.File instance
   180→func documentsFromFile(fi fs.File, opts SnapshotOption) ([]*ext.Document, error) {
   181→	validator, err := validation.NewFeaturesValidator(opts.validatorOption...)
   182→	if err != nil {
   183→		return nil, err
   184→	}
   185→
   186→	stat, err := fi.Stat()
   187→	if err != nil {
   188→		return nil, err
   189→	}
   190→
   191→	buf := &bytes.Buffer{}
   192→	reader := io.TeeReader(fi, buf)
   193→
   194→	var docs []*ext.Document
   195→	extn := filepath.Ext(stat.Name())
   196→
   197→	var decode func(any) error
   198→	switch extn {
   199→	case ".yaml", ".yml":
   200→		// Support YAML stream by looping until we reach an EOF.
   201→		decode = yaml.NewDecoder(buf).Decode
   202→	case "", ".json":
   203→		decode = json.NewDecoder(buf).Decode
   204→	default:
   205→		return nil, fmt.Errorf("unexpected extension: %q", extn)
   206→	}
   207→
   208→	// validate after we have checked supported
   209→	// extensions but before we attempt to decode the
   210→	// buffers contents to ensure we fill the buffer
   211→	// via the TeeReader
   212→	if err := validator.Validate(stat.Name(), reader); err != nil {
   213→		return nil, err
   214→	}
   215→
   216→	for {
   217→		doc := &ext.Document{}
   218→		if err := decode(doc); err != nil {
   219→			if errors.Is(err, io.EOF) {
   220→				break
   221→			}
   222→			return nil, err
   223→		}
   224→
   225→		// set namespace to default if empty in document
   226→		if doc.Namespace == "" {
   227→			doc.Namespace = "default"
   228→		}
   229→		docs = append(docs, doc)
   230→	}
   231→
   232→	return docs, nil
   233→}
   234→
   235→// listStateFiles lists all the file paths in a provided fs.FS containing Flipt feature state
   236→func listStateFiles(logger *zap.Logger, src fs.FS) ([]string, error) {
   237→	idx, err := OpenFliptIndex(logger, src)
   238→	if err != nil {
   239→		return nil, err
   240→	}
   241→
   242→	var paths []string
   243→	if err := fs.WalkDir(src, ".", func(path string, d fs.DirEntry, err error) error {
   244→		if err != nil {
   245→			return err
   246→		}
   247→
   248→		if d.IsDir() {
   249→			return nil
   250→		}
   251→
   252→		if idx.Match(path) {
   253→			paths = append(paths, path)
   254→		}
   255→
   256→		return nil
   257→	}); err != nil {
   258→		return nil, err
   259→	}
   260→
   261→	return paths, nil
   262→}
