   264→func (ss *Snapshot) addDoc(doc *ext.Document) error {
   265→	ns := ss.ns[doc.Namespace]
   266→	if ns == nil {
   267→		ns = newNamespace(doc.Namespace, doc.Namespace, ss.now)
   268→	}
   269→
   270→	evalDists := map[string][]*storage.EvaluationDistribution{}
   271→	if len(ss.evalDists) > 0 {
   272→		evalDists = ss.evalDists
   273→	}
   274→
   275→	for _, s := range doc.Segments {
   276→		matchType := flipt.MatchType_value[s.MatchType]
   277→		segment := &flipt.Segment{
   278→			NamespaceKey: doc.Namespace,
   279→			Name:         s.Name,
   280→			Key:          s.Key,
   281→			Description:  s.Description,
   282→			MatchType:    flipt.MatchType(matchType),
   283→			CreatedAt:    ss.now,
   284→			UpdatedAt:    ss.now,
   285→		}
   286→
   287→		for _, constraint := range s.Constraints {
   288→			constraintType := flipt.ComparisonType_value[constraint.Type]
   289→			segment.Constraints = append(segment.Constraints, &flipt.Constraint{
   290→				NamespaceKey: doc.Namespace,
   291→				SegmentKey:   segment.Key,
   292→				Id:           uuid.Must(uuid.NewV4()).String(),
   293→				Operator:     constraint.Operator,
   294→				Property:     constraint.Property,
   295→				Type:         flipt.ComparisonType(constraintType),
   296→				Value:        constraint.Value,
   297→				Description:  constraint.Description,
   298→				CreatedAt:    ss.now,
   299→				UpdatedAt:    ss.now,
   300→			})
   301→		}
   302→
   303→		ns.segments[segment.Key] = segment
   304→	}
   305→
   306→	for _, f := range doc.Flags {
   307→		flagType := flipt.FlagType_value[f.Type]
   308→		flag := &flipt.Flag{
   309→			NamespaceKey: doc.Namespace,
   310→			Key:          f.Key,
   311→			Name:         f.Name,
   312→			Description:  f.Description,
   313→			Enabled:      f.Enabled,
   314→			Type:         flipt.FlagType(flagType),
   315→			CreatedAt:    ss.now,
   316→			UpdatedAt:    ss.now,
   317→		}
   318→
   319→		for _, v := range f.Variants {
   320→			attachment, err := json.Marshal(v.Attachment)
   321→			if err != nil {
   322→				return err
   323→			}
   324→
   325→			flag.Variants = append(flag.Variants, &flipt.Variant{
   326→				Id:           uuid.Must(uuid.NewV4()).String(),
   327→				NamespaceKey: doc.Namespace,
   328→				Key:          v.Key,
   329→				Name:         v.Name,
   330→				Description:  v.Description,
   331→				Attachment:   string(attachment),
   332→				CreatedAt:    ss.now,
   333→				UpdatedAt:    ss.now,
   334→			})
   335→		}
   336→
   337→		ns.flags[f.Key] = flag
   338→
   339→		evalRules := []*storage.EvaluationRule{}
   340→		for i, r := range f.Rules {
   341→			rank := int32(i + 1)
   342→			rule := &flipt.Rule{
   343→				NamespaceKey: doc.Namespace,
   344→				Id:           uuid.Must(uuid.NewV4()).String(),
   345→				FlagKey:      f.Key,
   346→				Rank:         rank,
   347→				CreatedAt:    ss.now,
   348→				UpdatedAt:    ss.now,
   349→			}
   350→
   351→			evalRule := &storage.EvaluationRule{
   352→				NamespaceKey: doc.Namespace,
   353→				FlagKey:      f.Key,
   354→				ID:           rule.Id,
   355→				Rank:         rank,
   356→			}
   357→
   358→			switch s := r.Segment.IsSegment.(type) {
   359→			case ext.SegmentKey:
   360→				rule.SegmentKey = string(s)
   361→			case *ext.Segments:
   362→				rule.SegmentKeys = s.Keys
   363→				segmentOperator := flipt.SegmentOperator_value[s.SegmentOperator]
   364→
   365→				rule.SegmentOperator = flipt.SegmentOperator(segmentOperator)
   366→			}
   367→
   368→			var (
   369→				segmentKeys = []string{}
   370→				segments    = make(map[string]*storage.EvaluationSegment)
   371→			)
   372→
   373→			if rule.SegmentKey != "" {
   374→				segmentKeys = append(segmentKeys, rule.SegmentKey)
   375→			} else if len(rule.SegmentKeys) > 0 {
   376→				segmentKeys = append(segmentKeys, rule.SegmentKeys...)
   377→			}
   378→
   379→			for _, segmentKey := range segmentKeys {
   380→				segment := ns.segments[segmentKey]
   381→				if segment == nil {
   382→					return errs.ErrInvalidf("flag %s/%s rule %d references unknown segment %q", doc.Namespace, flag.Key, rank, segmentKey)
   383→				}
   384→
   385→				evc := make([]storage.EvaluationConstraint, 0, len(segment.Constraints))
   386→				for _, constraint := range segment.Constraints {
   387→					evc = append(evc, storage.EvaluationConstraint{
   388→						Operator: constraint.Operator,
   389→						Property: constraint.Property,
   390→						Type:     constraint.Type,
   391→						Value:    constraint.Value,
   392→					})
   393→				}
   394→
   395→				segments[segmentKey] = &storage.EvaluationSegment{
   396→					SegmentKey:  segmentKey,
   397→					MatchType:   segment.MatchType,
   398→					Constraints: evc,
   399→				}
   400→			}
   401→
   402→			if rule.SegmentOperator == flipt.SegmentOperator_AND_SEGMENT_OPERATOR {
   403→				evalRule.SegmentOperator = flipt.SegmentOperator_AND_SEGMENT_OPERATOR
   404→			}
   405→
   406→			evalRule.Segments = segments
   407→
   408→			evalRules = append(evalRules, evalRule)
   409→
   410→			for _, d := range r.Distributions {
   411→				variant, found := findByKey(d.VariantKey, flag.Variants...)
   412→				if !found {
   413→					return errs.ErrInvalidf("flag %s/%s rule %d references unknown variant %q", doc.Namespace, flag.Key, rank, d.VariantKey)
   414→				}
   415→
   416→				id := uuid.Must(uuid.NewV4()).String()
   417→				rule.Distributions = append(rule.Distributions, &flipt.Distribution{
   418→					Id:        id,
   419→					Rollout:   d.Rollout,
   420→					RuleId:    rule.Id,
   421→					VariantId: variant.Id,
   422→					CreatedAt: ss.now,
   423→					UpdatedAt: ss.now,
   424→				})
   425→
   426→				evalDists[evalRule.ID] = append(evalDists[evalRule.ID], &storage.EvaluationDistribution{
   427→					ID:                id,
   428→					Rollout:           d.Rollout,
   429→					VariantID:         variant.Id,
   430→					VariantKey:        variant.Key,
   431→					VariantAttachment: variant.Attachment,
   432→				})
   433→			}
   434→
   435→			ns.rules[rule.Id] = rule
   436→		}
   437→
   438→		ns.evalRules[f.Key] = evalRules
   439→
   440→		evalRollouts := make([]*storage.EvaluationRollout, 0, len(f.Rollouts))
   441→		for i, rollout := range f.Rollouts {
   442→			rank := int32(i + 1)
   443→			s := &storage.EvaluationRollout{
   444→				NamespaceKey: doc.Namespace,
   445→				Rank:         rank,
   446→			}
   447→
   448→			flagRollout := &flipt.Rollout{
   449→				Id:           uuid.Must(uuid.NewV4()).String(),
   450→				Rank:         rank,
   451→				FlagKey:      f.Key,
   452→				NamespaceKey: doc.Namespace,
   453→				CreatedAt:    ss.now,
   454→				UpdatedAt:    ss.now,
   455→			}
   456→
   457→			if rollout.Threshold != nil {
   458→				s.Threshold = &storage.RolloutThreshold{
   459→					Percentage: rollout.Threshold.Percentage,
   460→					Value:      rollout.Threshold.Value,
   461→				}
   462→				s.RolloutType = flipt.RolloutType_THRESHOLD_ROLLOUT_TYPE
   463→
   464→				flagRollout.Type = s.RolloutType
   465→				flagRollout.Rule = &flipt.Rollout_Threshold{
   466→					Threshold: &flipt.RolloutThreshold{
   467→						Percentage: rollout.Threshold.Percentage,
   468→						Value:      rollout.Threshold.Value,
   469→					},
   470→				}
   471→			} else if rollout.Segment != nil {
   472→				var (
   473→					segmentKeys = []string{}
   474→					segments    = make(map[string]*storage.EvaluationSegment)
   475→				)
   476→
   477→				if rollout.Segment.Key != "" {
   478→					segmentKeys = append(segmentKeys, rollout.Segment.Key)
   479→				} else if len(rollout.Segment.Keys) > 0 {
   480→					segmentKeys = append(segmentKeys, rollout.Segment.Keys...)
   481→				}
   482→
   483→				for _, segmentKey := range segmentKeys {
   484→					segment, ok := ns.segments[segmentKey]
   485→					if !ok {
   486→						return errs.ErrInvalidf("flag %s/%s rule %d references unknown segment %q", doc.Namespace, flag.Key, rank, segmentKey)
   487→					}
   488→
   489→					constraints := make([]storage.EvaluationConstraint, 0, len(segment.Constraints))
   490→					for _, c := range segment.Constraints {
   491→						constraints = append(constraints, storage.EvaluationConstraint{
   492→							Operator: c.Operator,
   493→							Property: c.Property,
   494→							Type:     c.Type,
   495→							Value:    c.Value,
   496→						})
   497→					}
   498→
   499→					segments[segmentKey] = &storage.EvaluationSegment{
   500→						SegmentKey:  segmentKey,
   501→						MatchType:   segment.MatchType,
   502→						Constraints: constraints,
   503→					}
   504→				}
   505→
   506→				segmentOperator := flipt.SegmentOperator_value[rollout.Segment.Operator]
   507→
   508→				s.Segment = &storage.RolloutSegment{
   509→					Segments:        segments,
   510→					SegmentOperator: flipt.SegmentOperator(segmentOperator),
   511→					Value:           rollout.Segment.Value,
   512→				}
   513→
   514→				s.RolloutType = flipt.RolloutType_SEGMENT_ROLLOUT_TYPE
   515→
   516→				frs := &flipt.RolloutSegment{
   517→					Value:           rollout.Segment.Value,
   518→					SegmentOperator: flipt.SegmentOperator(segmentOperator),
   519→				}
   520→
   521→				if len(segmentKeys) == 1 {
   522→					frs.SegmentKey = segmentKeys[0]
   523→				} else {
   524→					frs.SegmentKeys = segmentKeys
   525→				}
   526→
   527→				flagRollout.Type = s.RolloutType
   528→				flagRollout.Rule = &flipt.Rollout_Segment{
   529→					Segment: frs,
   530→				}
   531→			}
   532→
   533→			ns.rollouts[flagRollout.Id] = flagRollout
   534→
   535→			evalRollouts = append(evalRollouts, s)
   536→		}
   537→
   538→		ns.evalRollouts[f.Key] = evalRollouts
   539→	}
   540→
   541→	ss.ns[doc.Namespace] = ns
   542→
   543→	ss.evalDists = evalDists
   544→
   545→	return nil
   546→}
